import{_ as t,o as i,c as o,ag as a}from"./chunks/framework.B9unkguw.js";const h=JSON.parse('{"title":"Generated Settings Pages","description":"","frontmatter":{},"headers":[],"relativePath":"en/qgc-dev-guide/views/settings_generation.md","filePath":"en/qgc-dev-guide/views/settings_generation.md"}'),n={name:"en/qgc-dev-guide/views/settings_generation.md"};function s(r,e,l,d,c,g){return i(),o("div",null,e[0]||(e[0]=[a('<h1 id="generated-settings-pages" tabindex="-1">Generated Settings Pages <a class="header-anchor" href="#generated-settings-pages" aria-label="Permalink to &quot;Generated Settings Pages&quot;">​</a></h1><p>This page explains how the Application Settings pages are generated from JSON definitions and how to extend them.</p><p>For the complete JSON schema reference see <a href="./../../../../tools/generators/settings_qml/README.html">tools/generators/settings_qml/README.md</a>.</p><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>The runtime stack is:</p><ol><li>Fact metadata in <code>src/Settings/*.SettingsGroup.json</code></li><li>Settings Fact accessors in <code>src/Settings/*Settings.h/.cc</code></li><li>Settings UI page definitions in <code>src/AppSettings/pages/*.SettingsUI.json</code></li><li>Page list in <code>src/AppSettings/pages/SettingsPages.json</code></li><li>Python generator in <code>tools/generators/settings_qml</code></li><li>Generated QML loaded by <code>src/QmlControls/AppSettings.qml</code></li></ol><p>At build time, CMake runs the generator and places generated QML in the build tree. Those files are then compiled into the <code>QGroundControl.AppSettings</code> QML module.</p><h2 id="where-generation-is-wired" tabindex="-1">Where Generation Is Wired <a class="header-anchor" href="#where-generation-is-wired" aria-label="Permalink to &quot;Where Generation Is Wired&quot;">​</a></h2><p>Generation is configured in <a href="../../../../src/AppSettings/CMakeLists.txt">src/AppSettings/CMakeLists.txt</a>:</p><ul><li>Custom command runs: <ul><li><code>python -m tools.generators.settings_qml.generate_pages --output-dir &lt;build&gt;/generated</code></li></ul></li><li>Inputs: <ul><li><code>src/AppSettings/pages/*.json</code></li><li><code>src/Settings/*.SettingsGroup.json</code></li></ul></li><li>Outputs: <ul><li>Generated page QML files (e.g. <code>GeneralSettings.qml</code>, <code>FlyViewSettings.qml</code>)</li><li><code>SettingsPagesModel.qml</code></li></ul></li></ul><p>The generator entry point is <a href="./../../../../tools/generators/settings_qml/generate_pages.py.html">tools/generators/settings_qml/generate_pages.py</a>, with most logic in <a href="./../../../../tools/generators/settings_qml/page_generator.py.html">tools/generators/settings_qml/page_generator.py</a>.</p><h2 id="how-controls-are-chosen" tabindex="-1">How Controls Are Chosen <a class="header-anchor" href="#how-controls-are-chosen" aria-label="Permalink to &quot;How Controls Are Chosen&quot;">​</a></h2><p>When <code>control</code> is omitted in a <code>*.SettingsUI.json</code>, the generator reads the fact&#39;s type from <code>*.SettingsGroup.json</code> metadata to auto-detect:</p><ul><li><code>bool</code> → checkbox</li><li>Enum-backed facts → combobox</li><li>Other types → text field</li></ul><p>An explicit <code>control</code> key overrides auto-selection.</p><h2 id="sidebar-sections-and-search" tabindex="-1">Sidebar, Sections, and Search <a class="header-anchor" href="#sidebar-sections-and-search" aria-label="Permalink to &quot;Sidebar, Sections, and Search&quot;">​</a></h2><p>The generated <code>SettingsPagesModel.qml</code> is built from <code>SettingsPages.json</code> and each page definition.</p><p>It includes:</p><ul><li><code>sections</code>: section names for expandable sidebar rows</li><li><code>searchTerms</code>: page/section/fact keyword tokens used by the search field in <a href="./../../../../src/QmlControls/AppSettings.qml.html">src/QmlControls/AppSettings.qml</a></li></ul><p>Search terms are derived from:</p><ul><li>Page name</li><li>Section heading/section name</li><li>Fact metadata <code>keywords</code></li><li>Group-level <code>keywords</code> when using <code>component</code> groups without explicit controls</li></ul><h2 id="add-a-new-setting-to-an-existing-generated-page" tabindex="-1">Add a New Setting to an Existing Generated Page <a class="header-anchor" href="#add-a-new-setting-to-an-existing-generated-page" aria-label="Permalink to &quot;Add a New Setting to an Existing Generated Page&quot;">​</a></h2><ol><li><p>Add a Fact metadata entry to the appropriate <code>src/Settings/&lt;Group&gt;.SettingsGroup.json</code> file.</p></li><li><p>Expose that Fact through the corresponding settings class:</p><ul><li>Add <code>DEFINE_SETTINGFACT(&lt;factName&gt;)</code> in the matching <code>*Settings.h</code>.</li><li>Ensure <code>DECLARE_SETTINGSFACT</code> exists in <code>*Settings.cc</code> if required by that file pattern.</li></ul></li><li><p>Add a control entry in the page JSON:</p><ul><li>File: <code>src/AppSettings/pages/&lt;Page&gt;.SettingsUI.json</code></li><li>Add: <code>{ &quot;setting&quot;: &quot;&lt;accessor&gt;.&lt;factName&gt;&quot; }</code></li></ul><p>See <a href="./../../../../tools/generators/settings_qml/README.html">tools/generators/settings_qml/README.md</a> for the full JSON schema.</p></li><li><p>Build. CMake regenerates the QML page automatically.</p></li></ol><h2 id="add-a-new-generated-settings-page" tabindex="-1">Add a New Generated Settings Page <a class="header-anchor" href="#add-a-new-generated-settings-page" aria-label="Permalink to &quot;Add a New Generated Settings Page&quot;">​</a></h2><ol><li>Create a new page definition JSON in <code>src/AppSettings/pages</code>, e.g. <code>MyFeature.SettingsUI.json</code>.</li><li>Add a new entry to <code>src/AppSettings/pages/SettingsPages.json</code>: <ul><li><code>name</code>, <code>icon</code>, <code>qml</code> (output filename), <code>pageDefinition</code> (your new JSON file)</li><li>Optional <code>visible</code> expression</li></ul></li><li>Update the generated outputs list in <a href="../../../../src/AppSettings/CMakeLists.txt">src/AppSettings/CMakeLists.txt</a>: <ul><li>Add your new QML filename to <code>_generated_qml_names</code>.</li></ul></li><li>Build QGC to generate and include the new page.</li></ol><h2 id="important-notes" tabindex="-1">Important Notes <a class="header-anchor" href="#important-notes" aria-label="Permalink to &quot;Important Notes&quot;">​</a></h2><ul><li>If a page in <code>SettingsPages.json</code> has no <code>pageDefinition</code>, it is treated as hand-written QML/URL content and not generated.</li><li>The CMake <code>_generated_qml_names</code> list is explicit. If you forget to add a new output filename, build integration will be incomplete.</li><li>The <code>setting</code> path in <code>*.SettingsUI.json</code> must match a valid <code>QGroundControl.settingsManager.&lt;group&gt;.&lt;fact&gt;</code> accessor.</li><li>Fact labels should be present in metadata. Missing labels are logged at runtime by <code>SettingsGroup</code>.</li></ul>',27)]))}const u=t(n,[["render",s]]);export{h as __pageData,u as default};
